import{_ as t,o,c as i,a3 as a}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"Module Development Standard","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Module Development Standard | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/module-development"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Module Development Standard | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/module-development"}]]},"headers":[],"relativePath":"developer-guide/module-development.md","filePath":"developer-guide/module-development.md","lastUpdated":1784419868000}'),n={name:"developer-guide/module-development.md"};function r(d,e,s,l,c,u){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="module-development-standard" tabindex="-1">Module Development Standard <a class="header-anchor" href="#module-development-standard" aria-label="Permalink to &quot;Module Development Standard&quot;">​</a></h1><p>Every business capability on this platform is a <strong>module</strong>. Modules are licensed via the marketplace catalog and authorized via Spatie permissions. They are <strong>not</strong> PHP packages or plugins.</p><p><strong>Reference implementation:</strong> <a href="/user-guide/leads-overview">Leads</a></p><h2 id="guides" tabindex="-1">Guides <a class="header-anchor" href="#guides" aria-label="Permalink to &quot;Guides&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Audience</th><th>Document</th></tr></thead><tbody><tr><td>Engineers</td><td><a href="/developer-guide/module-development-guide">module-development-developer.md</a></td></tr><tr><td>Production / ops</td><td><a href="/deployment/module-development">module-development-production.md</a></td></tr><tr><td>Documentation</td><td><a href="/developer-guide/documentation-governance">documentation-governance.md</a></td></tr><tr><td>Architecture freeze</td><td><a href="/getting-started/platform-freeze">../architecture/platform-freeze.md</a></td></tr><tr><td>Module architecture</td><td><a href="/architecture/module-architecture">module-architecture.md</a></td></tr><tr><td>Module dependencies</td><td><a href="/architecture/module-dependencies">module-dependencies.md</a></td></tr><tr><td>Module licensing</td><td><a href="/architecture/module-licensing">module-licensing.md</a></td></tr><tr><td>Notification contracts</td><td><a href="/developer-guide/notification-architecture-contract">notification-architecture-contract.md</a></td></tr></tbody></table><h2 id="principles" tabindex="-1">Principles <a class="header-anchor" href="#principles" aria-label="Permalink to &quot;Principles&quot;">​</a></h2><ol><li><strong>Consistency over abstraction</strong> — flat Laravel layout; register through existing catalog, permissions, middleware, nav, and settings.</li><li><strong>Licensing ≠ authorization</strong> — <code>module:{slug}</code> then <code>can:{slug}.{action}</code>.</li><li><strong>Mirror Leads</strong> — Tasks, Communication Templates, Invoices, Inventory, Purchases, HR, Payroll, Accounting, Assets, Projects must follow the same licensing + permission + UI structure (Communication Templates is additionally a cross-cutting consumer pattern).</li><li><strong>No shortcuts</strong> — every module ships backend, frontend, tests, docs, and CHANGELOG in the <strong>same delivery</strong> (<a href="/developer-guide/documentation-governance">Documentation Governance</a>).</li><li><strong>Migrate-only production</strong> — new default modules and permissions ship as data migrations; never production <code>db:seed</code> for catalog/RBAC.</li><li><strong>Self-contained modules</strong> — each module owns its migrations, models, services, routes, UI, permissions, settings, docs, and tests; communicate through contracts/services only. See <a href="/architecture/module-architecture">Module Architecture</a>.</li><li><strong>Declare dependencies</strong> — required vs optional; free vs billable. See <a href="/architecture/module-dependencies">Module Dependencies</a>.</li><li><strong>Independent licensing</strong> — design every module so it can be included, free, or billable. See <a href="/architecture/module-licensing">Module Licensing</a>.</li></ol><h2 id="cross-cutting-patterns-sprint-2" tabindex="-1">Cross-cutting patterns (Sprint 2+) <a class="header-anchor" href="#cross-cutting-patterns-sprint-2" aria-label="Permalink to &quot;Cross-cutting patterns (Sprint 2+)&quot;">​</a></h2><ul><li><strong>Dashboard widgets</strong> — register via <code>DashboardWidgetService</code> on <code>GET /dashboard</code>; gate by module entitlement, permission, and assignee scope. Do not add a Calendar widget until the Calendar module exists.</li><li><strong>Notifications</strong> — Follow the frozen <a href="/developer-guide/notification-architecture-contract">Notification Architecture Contract</a>: versioned payload, route descriptors, NotificationBatch aggregation, Reverb/Echo realtime, modular SPA registry. Due/overdue work uses <code>crm:send-due-notifications</code>. Retention: <code>notifications:prune</code>.</li><li><strong>Assignee scoping</strong> — reuse <code>ScopesToAssignee</code> so users without <code>{slug}.assign</code> only see their own records.</li></ul><h2 id="definition-of-done" tabindex="-1">Definition of Done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of Done&quot;">​</a></h2><p>A module is complete only when:</p><ul><li>[ ] Backend implementation complete (models, migrations, services, controllers, requests, resources, policies, events, notifications)</li><li>[ ] Frontend complete (pages, forms, tables, filters, dialogs/drawers, loading/empty/error states)</li><li>[ ] Permissions enforced (Spatie + UI gates)</li><li>[ ] Module licensing enforced (<code>module:</code> middleware + SPA nav)</li><li>[ ] Tenant isolation verified</li><li>[ ] Audit logging (<code>PlatformAuditService</code>) implemented</li><li>[ ] Activity logging (Spatie <code>LogsActivity</code> + domain timeline where applicable)</li><li>[ ] Notifications implemented where applicable</li><li>[ ] Pest tests pass (CRUD, authz, validation, tenant isolation, module gate)</li><li>[ ] Playwright suite passes (<code>test:e2e:{slug}</code>)</li><li>[ ] Manual browser QA passes</li><li>[ ] Developer / User / Production guides updated <strong>in the same PR</strong> (<a href="/developer-guide/documentation-governance">Documentation Governance</a>)</li><li>[ ] API + database docs updated</li><li>[ ] CHANGELOG updated</li><li>[ ] No console errors; no failed network requests; build passes</li><li>[ ] No platform refactor required before the next module</li></ul>',12)])])}const g=t(n,[["render",r]]);export{p as __pageData,g as default};
